mapper.sql:
SELECT o.id, o.order_no, o.user_id, u.nickname, u.email, o.plan_key, o.cycle, o.amount, o.status, o.paid_at, o.refunded_at, o.refund_reason, o.admin_remark, o.operator_id, o.created_at FROM u_order o LEFT JOIN u_user u ON u.id = o.user_id AND u.is_deleted = 0 WHERE 1 = 1
AND (u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%'))
AND o.plan_key = #{planKey}
AND o.status = #{status}
AND o.created_at >= CONCAT(#{startDate}, ' 00:00:00')
AND o.created_at <= CONCAT(#{endDate}, ' 23:59:59')

mapper.select:
SELECT COUNT(*) FROM u_order o LEFT JOIN u_user u ON u.id = o.user_id AND u.is_deleted = 0 WHERE 1 = 1
AND (u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%'))
AND o.plan_key = #{planKey}
AND o.status = #{status}
AND o.created_at >= CONCAT(#{startDate}, ' 00:00:00')
AND o.created_at <= CONCAT(#{endDate}, ' 23:59:59')
